def require_auth(f):
    """Authentication decorator to verify tenant API keys."""
    @wraps(f)
    def decorated(*args, **kwargs):
        api_key = request.headers.get('X-API-Key')
        tenant_id = request.headers.get('X-Tenant-ID')

        if not api_key or not tenant_id:
            return jsonify({"error": "Missing authentication headers"}), 401

        if tenant_id not in API_KEYS or API_KEYS[tenant_id] != api_key:
            return jsonify({"error": "Invalid authentication"}), 403

        g.tenant_id = tenant_id
        return f(*args, **kwargs)
    return decorated


def get_tenant_dir(tenant_id: str) -> Path:
    """Get isolated directory for a tenant's models."""
    tenant_dir = Path(UPLOAD_FOLDER) / secure_filename(tenant_id)
    tenant_dir.mkdir(parents=True, exist_ok=True)
    return tenant_dir


def compute_file_hash(file_bytes: bytes) -> str:
    """Compute SHA-256 hash of file contents."""
    return hashlib.sha256(file_bytes).hexdigest()


def detect_pickle_in_bytes(data: bytes) -> bool:
    """
    Detect if binary data contains pickle opcodes.
    This helps reject files that disguise pickle payloads.
    """
    # Pickle protocol magic bytes / opcodes
    PICKLE_OPCODES = [
        b'\x80',  # PROTO
        b'c',     # GLOBAL (used for importing modules - common in exploits)
        b'\x85',  # TUPLE1
        b'R',     # REDUCE (calls callable - dangerous)
        b'i',     # INST
        b'o',     # OBJ
        b'\x81',  # NEWOBJ
        b'\x92',  # NEWOBJ_EX
    ]

    # Check for dangerous pickle opcodes that indicate code execution
    dangerous_patterns = [
        b'cos\nsystem',      # os.system
        b'cposix\nsystem',   # posix.system
        b'csubprocess',      # subprocess module
        b'cbuiltins\neval',  # eval
        b'cbuiltins\nexec',  # exec
        b'c__builtin__',     # __builtin__
        b'cnt\nsystem',      # nt.system (Windows)
        b'cos\npopen',       # os.popen
        b'creduce',          # reduce
        b'cwebbrowser',      # webbrowser
        b'__reduce__',
        b'__reduce_ex__',
    ]

    for pattern in dangerous_patterns:
        if pattern in data:
            return True

    return False


def scan_pickle_safety(file_bytes: bytes) -> Dict[str, Any]:
    """
    Use fickling to analyze pickle file for safety issues.
    Returns a report of findings.
    """
    report = {
        "safe": True,
        "warnings": [],
        "dangerous_imports": [],
        "severity": "none"
    }

    # Check for dangerous patterns in raw bytes
    if detect_pickle_in_bytes(file_bytes):
        report["safe"] = False
        report["warnings"].append("Dangerous pickle opcodes detected in file")
        report["severity"] = "critical"
        return report

    if FICKLING_AVAILABLE:
        try:
            fickled = Fickling.load(io.BytesIO(file_bytes))

            if fickled.is_likely_safe is False:
                report["safe"] = False
                report["severity"] = "critical"
                report["warnings"].append("Fickling detected unsafe pickle content")

            # Check for dangerous imports/calls
            for node in fickled.ast.body:
                node_str = str(node)
                dangerous_modules = [
                    'os', 'subprocess', 'sys', 'builtins', 'shutil',
                    'socket', 'http', 'urllib', 'ctypes', 'importlib',
                    'code', 'codeop', 'compile', 'compileall',
                    'webbrowser', 'antigravity', 'turtle',
                ]
                for mod in dangerous_modules:
                    if mod in node_str:
                        report["safe"] = False
                        report["dangerous_imports"].append(mod)
                        report["severity"] = "critical"

        except Exception as e:
            report["warnings"].append(f"Fickling analysis error: {str(e)}")
            report["safe"] = False
            report["severity"] = "high"

    return report


def validate_onnx_model(file_bytes: bytes) -> Dict[str, Any]:
    """Validate an ONNX model file."""
    report = {"valid": False, "error": None}

    if not ONNX_AVAILABLE:
        report["error"] = "ONNX runtime not available"
        return report

    try:
        # Write to temp file for validation
        with tempfile.NamedTemporaryFile(suffix='.onnx', delete=False) as tmp:
            tmp.write(file_bytes)
            tmp_path = tmp.name

        try:
            # Validate by attempting to create an inference session
            # Disable all optimizations for safety during validation
            sess_options = ort.SessionOptions()
            sess_options.graph_optimization_level = ort.GraphOptimizationLevel.ORT_DISABLE_ALL

            session = ort.InferenceSession(tmp_path, sess_options)

            report["valid"] = True
            report["inputs"] = [
                {"name": inp.name, "shape": inp.shape, "type": inp.type}
                for inp in session.get_inputs()
            ]
            report["outputs"] = [
                {"name": out.name, "shape": out.shape, "type": out.type}
                for out in session.get_outputs()
            ]
        finally:
            os.unlink(tmp_path)

    except Exception as e:
        report["error"] = f"ONNX validation failed: {str(e)}"

    return report


def validate_skops_model(file_bytes: bytes) -> Dict[str, Any]:
    """Validate a skops model file for safety."""
    report = {"valid": False, "error": None, "untrusted_types": []}

    if not SKOPS_AVAILABLE:
        report["error"] = "skops not available"
        return report

    try:
        # skops provides safe deserialization with type checking
        # First, get the list of untrusted types without loading
        unknown_types = skops_io.get_untrusted_types(data=file_bytes)

        report["untrusted_types"] = [str(t) for t in unknown_types]

        # Define allowlist of safe sklearn/numpy types
        SAFE_TYPE_PREFIXES = [
            "sklearn.",
            "numpy.",
            "scipy.",
            "xgboost.",
            "lightgbm.",
        ]

        # Check all untrusted types are from safe packages
        unsafe_types = []
        for t in unknown_types:
            t_str = str(t)
            if not any(t_str.startswith(prefix) for prefix in SAFE_TYPE_PREFIXES):
                unsafe_types.append(t_str)

        if unsafe_types:
            report["error"] = f"Unsafe types found: {unsafe_types}"
            report["unsafe_types"] = unsafe_types
        else:
            report["valid"] = True
            report["trusted_types"] = [str(t) for t in unknown_types]

    except Exception as e:
        report["error"] = f"skops validation failed: {str(e)}"

    return report


def load_model(model_info: Dict[str, Any]) -> Any:
    """Safely load a model based on its format."""
    model_path = model_info["path"]
    model_format = model_info["format"]

    with open(model_path, "rb") as f:
        file_bytes = f.read()

    if model_format == "onnx":
        if not ONNX_AVAILABLE:
            raise RuntimeError("ONNX runtime not available")
        sess_options = ort.SessionOptions()
        sess_options.graph_optimization_level = ort.GraphOptimizationLevel.ORT_DISABLE_ALL
        return ort.InferenceSession(model_path, sess_options)

    elif model_format == "skops":
        if not SKOPS_AVAILABLE:
            raise RuntimeError("skops not available")

        # Re-validate before loading
        unknown_types = skops_io.get_untrusted_types(data=file_bytes)

        SAFE_TYPE_PREFIXES = [
            "sklearn.", "numpy.", "scipy.", "xgboost.", "lightgbm.",
        ]

        safe_types = []
        for t in unknown_types:
            t_str = str(t)
            if any(t_str.startswith(prefix) for prefix in SAFE_TYPE_PREFIXES):
                safe_types.append(t)
            else:
                raise RuntimeError(f"Unsafe type detected during load: {t_str}")

        # Load with explicit trusted types only
        return skops_io.loads(file_bytes, trusted=safe_types)

    else:
        raise ValueError(f"Unsupported model format: {model_format}")


