@app.route('/api/v1/models', methods=['POST'])
@require_auth
def upload_model():
    """
    Upload a model file for the authenticated tenant.

    SECURITY: We explicitly DO NOT support pickle (.pkl, .pickle) files.
    Only ONNX and skops formats are accepted as they provide safe
    deserialization without arbitrary code execution.
    """
    tenant_id = g.tenant_id

    if 'model' not in request.files:
        return jsonify({"error": "No model file provided"}), 400

    file = request.files['model']
    model_name = request.form.get('name', 'unnamed_model')

    if file.filename == '':
        return jsonify({"error": "No file selected"}), 400

    # Check file extension
    filename = secure_filename(file.filename)
    file_ext = Path(filename).suffix.lower()

    if file_ext not in ALLOWED_EXTENSIONS:
        return jsonify({
            "error": f"Unsupported file format: {file_ext}",
            "message": (
                "Only .onnx and .skops formats are supported. "
                "Pickle files (.pkl, .pickle) are NOT accepted due to "
                "arbitrary code execution vulnerabilities. "
                "Please convert your model to ONNX format or use skops "
                "for scikit-learn models."
            ),
            "supported_formats": list(ALLOWED_EXTENSIONS),
            "conversion_help": {
                "onnx": "Use sklearn-onnx, tf2onnx, or torch.onnx.export()",
                "skops": "Use skops.io.dump(model, file) instead of pickle.dump()"
            }
        }), 415

    # Read file bytes for validation
    file_bytes = file.read()

    # CRITICAL SECURITY CHECK: Scan for hidden pickle payloads
    # regardless of file extension
    if detect_pickle_in_bytes(file_bytes):
        return jsonify({
            "error": "Security violation: pickle payload detected in uploaded file",
            "message": "The uploaded file contains pickle serialization opcodes "
                       "which could enable arbitrary code execution. This upload "
                       "has been rejected."
        }), 422

    # Compute file hash for integrity
    file_hash = compute_file_hash(file_bytes)

    # Format-specific validation
    if file_ext == '.onnx':
        validation = validate_onnx_model(file_bytes)
        if not validation["valid"]:
            return jsonify({
                "error": "ONNX model validation failed",
                "details": validation["error"]
            }), 422
        model_format = "onnx"
        model_metadata = {
            "inputs": validation.get("inputs", []),
            "outputs": validation.get("outputs", []),
        }

    elif file_ext == '.skops':
        validation = validate_skops_model(file_bytes)
        if not validation["valid"]:
            return jsonify({
                "error": "skops model validation failed",
                "details": validation.get("error"),
                "unsafe_types": validation.get("unsafe_types", []),
            }), 422
        model_format = "skops"
        model_metadata = {
            "trusted_types": validation.get("trusted_types", []),
        }
    else:
        return jsonify({"error": "Unsupported format"}), 415

    # Save the validated model
    model_id = str(uuid.uuid4())
    tenant_dir = get_tenant_dir(tenant_id)
    model_path = tenant_dir / f"{model_id}{file_ext}"

    with open(model_path, 'wb') as f:
        f.write(file_bytes)

    # Register model
    if tenant_id not in model_registry:
        model_registry[tenant_id] = {}

    model_registry[tenant_id][model_id] = {
        "model_id": model_id,
        "name": model_name,
        "format": model_format,
        "path": str(model_path),
        "hash": file_hash,
        "size_bytes": len(file_bytes),
        "metadata": model_metadata,
    }

    return jsonify({
        "model_id": model_id,
        "name": model_name,
        "format": model_format,
        "hash": file_hash,
        "size_bytes": len(file_bytes),
        "metadata": model_metadata,
        "message": "Model uploaded and validated successfully"
    }), 201


