@app.route('/api/v1/models/<model_id>', methods=['DELETE'])
@require_auth
def delete_model(model_id):
    """Delete a model."""
    tenant_id = g.tenant_id
    models = model_registry.get(tenant_id, {})

    if model_id not in models:
        return jsonify({"error": "Model not found"}), 404

    model_info = models[model_id]
    model_path = Path(model_info["path"])

    # Remove file
    if model_path.exists():
        os.unlink(model_path)

    # Remove from registry
    del models[model_id]

    return jsonify({"message": f"Model {model_id} deleted successfully"})


@app.route('/api/v1/models/<model_id>/predict', methods=['POST'])
@require_auth
def predict(model_id):
    """
    Run inference on a model.

    Expects JSON body with 'input' field containing the input data.
    """
    tenant_id = g.tenant_id
    models = model_registry.get(tenant_id, {})

    if model_id not in models:
        return jsonify({"error": "Model not found"}), 404

    model_info = models[model_id]

    # Parse input data
    data = request.get_json()
    if not data or 'input' not in data:
        return jsonify({"error": "Request body must contain 'input' field"}), 400

    input_data = data['input']

    try:
        model = load_model(model_info)
    except Exception as e:
        return jsonify({"error": f"Failed to load model: {str(e)}"}), 500

    try:
        if model_info["format"] == "onnx":
            # ONNX inference
            input_array = np.array(input_data, dtype=np.float32)

            # Get expected input info
            input_info = model.get_inputs()[0]
            input_name = input_info.name

            # Reshape if needed
            expected_shape = input_info.shape
            if expected_shape and len(expected_shape) > 1:
                if input_array.ndim == 1:
                    input_array = input_array.reshape(1, -1)

            results = model.run(None, {input_name: input_array})

            # Format output
            output_names = [out.name for out in model.get_outputs()]
            predictions = {}
            for name, result in zip(output_names, results):
                if isinstance(result, np.ndarray):
                    predictions[name] = result.tolist()
                else:
                    predictions[name] = result

            return jsonify({
                "model_id": model_id,
                "predictions": predictions
            })

        elif model_info["format"] == "skops":
            # scikit-learn model inference via skops
            input_array = np.array(input_data)
            if input_array.ndim == 1:
                input_array = input_array.reshape(1, -1)

            # Try predict
            if hasattr(model, 'predict'):
                predictions = model.predict(input_array).tolist()
            else:
                return jsonify({"error": "Model does not support predict()"}), 400

            result = {"model_id": model_id, "predictions": predictions}

            # Also try predict_proba if available
            if hasattr(model, 'predict_proba'):
                try:
                    probabilities = model.predict_proba(input_array).tolist()
                    result["probabilities"] = probabilities
                except Exception:
                    pass

            return jsonify(result)

        else:
            return jsonify({"error": f"Unsupported format: {model_info['format']}"}), 400

    except Exception as e:
        return jsonify({"error": f"Inference failed: {str(e)}"}), 500


@app.route('/api/v1/security/scan', methods=['POST'])
@require_auth
def scan_file():
    """
    Security scanning endpoint.
    Upload any file to check if it contains dangerous pickle payloads.
    This does NOT save the file - it only scans it.
    """
    if 'file' not in request.files:
        return jsonify({"error": "No file provided"}), 400

    file = request.files['file']
    file_bytes = file.read()

    report = {
        "filename": secure_filename(file.filename),
        "size_bytes": len(file_bytes),
        "hash": compute_file_hash(file_bytes),
        "contains_pickle": detect_pickle_in_bytes(file_bytes),
    }

    # If it looks like a pickle file, do deep analysis
    file_ext = Path(file.filename).suffix.lower()
    if file_ext in ('.pkl', '.pickle', '.joblib'):
        report["pickle_analysis"] = scan_pickle_safety(file_bytes)
        report["recommendation"] = (
            "REJECT - Convert to ONNX or skops format for safe serving. "
            "Never use pickle.load() on untrusted data."
        )
    elif file_ext == '.onnx':
        report["onnx_validation"] = validate_onnx_model(file_bytes)
    elif file_ext == '.skops':
        report["skops_validation"] = validate_skops_model(file_bytes)

    return jsonify(report)


